MOD = 10**9 + 7

class Solution:
    def possibleStringCount(self, word: str, k: int) -> int:
        if not word:
            return 0

        # Split the word into runs of consecutive characters
        runs = []
        current_char = word[0]
        count = 1
        for c in word[1:]:
            if c == current_char:
                count += 1
            else:
                runs.append(count)
                current_char = c
                count = 1
        runs.append(count)

        n = len(runs)
        if n == 0:
            return 0

        # Initialize DP array
        dp = [0] * (k + 1)
        dp[0] = 1

        for m in runs:
            dp_new = [0] * (k + 1)
            diff = [0] * (k + 2)  # To handle range updates

            for s in range(k + 1):
                if dp[s] == 0:
                    continue
                # Calculate the maximum t such that s + t <= k - 1
                t = min(m, k - s - 1)
                if t >= 1:
                    start = s + 1
                    end = s + t
                    if end > k:
                        end = k
                    if start > end:
                        continue
                    # Update the difference array
                    diff[start] = (diff[start] + dp[s]) % MOD
                    if end + 1 <= k:
                        diff[end + 1] = (diff[end + 1] - dp[s]) % MOD

            # Compute the prefix sum to get the new dp values
            current = 0
            for s in range(k + 1):
                current = (current + diff[s]) % MOD
                dp_new[s] = (dp_new[s] + current) % MOD

            # Handle the cases where the sum is >= k
            for s in range(k + 1):
                a = max(1, k - s)
                if a > m:
                    count_ge = 0
                else:
                    count_ge = m - a + 1
                dp_new[k] = (dp_new[k] + dp[s] * count_ge) % MOD

            dp = dp_new

        return dp[k] % MOD

